window.customIcons = window.customIcons || {};
window.customIcons["sims2"] = {
  // HA calls getIcon(name) and expects { path, viewBox } where path is the
  // inner SVG markup to render inside an <svg>.
  // Prepend gradient definitions so each icon renders with faceted depth.
  getIcon: async function getIcon(name) {
    const inner = SIMS2_ICONS[name];
    if (!inner) {
      return undefined;
    }
    return { path: GRADIENT_DEFS + inner, viewBox: SIMS2_VIEWBOX };
  },
  // Optional: advertise the available names so icon pickers can list them.
  getPattern: undefined,
  names: Object.keys(SIMS2_ICONS),
};

// Tell Home Assistant to activate the custom icon set. Some HA versions only
// wire card-renderers to hass.icons when the "connection-ready" event fires,
// so register both eagerly (for early-load bundles) and on the event (for
// late-loading ones).
(function () {
  const hass = window.hass;
  if (hass && hass.icons) {
    hass.icons.register(window.customIcons["sims2"]);
  }
  window.addEventListener("connection-ready", function () {
    window.hass?.icons?.register(window.customIcons["sims2"]);
  });
})();

// Announce availability for tooling / debugging.
window.sims2Icons = window.sims2Icons || {
  prefix: "sims2",
  count: Object.keys(SIMS2_ICONS).length,
  names: Object.keys(SIMS2_ICONS),
};

/* ============================================================ sims2-loading-card.js — customElements.define(sims2-loading) ============================================================ */
/**
 * sims2-loading-card.js
 * ---------------------------------------------------------------------------
 * Custom Lovelace card:  custom:sims2-loading
 *
 * Renders a full-screen "The Sims 2" style loading experience inside a
 * Home Assistant dashboard:
 *   - deep blue Pleasantview sky gradient
 *   - a glowing, faceted plumbob that bobs and shifts mood
 *   - the gold "THE SIMS 2" style wordmark (customisable)
 *   - rotating, ridiculous loading tips ("Reticulating splines", and friends)
 *
 * Drop it in as the only card on a dedicated view to use as a splash screen,
 * or at the top of any dashboard. It auto-dismisses, can be bound to an
 * entity, or can stay up forever as a bit of ambient decor.
 *
 * No build step, no dependencies. Vanilla web component, Shadow DOM.
 *
 * Example configuration:
 *
 *   type: custom:sims2-loading
 *   wordmark: PLEASANTVIEW
 *   duration: 6                 # seconds before auto-dismiss (0 = forever)
 *   fullscreen: true            # overlay the whole viewport
 *   tips:                       # optional: override the built-in tip list
 *     - Reticulating your Zigbee mesh
 *     - Convincing the thermostat it is happy
 *
 * This file is a fan tribute. "The Sims 2" is a trademark of Electronic Arts.
 * ---------------------------------------------------------------------------
 */

const SIMS2_DEFAULT_TIPS = [
  // ---- canonical Maxis / Sims loading-screen lines -------------------------
  "Reticulating splines",
  "Reticulating splines… unreticulating splines",
  "Inserting chaos generator",
  "Herding llamas",
  "Consulting the oracle",
  "Fabricating imaginary infrastructure",
  "Interpreting family values",
  "Recomputing mammal matrix",
  "Engaging the autopet",
  "Simulating the simulation",
  "Polishing the plumbob",
  "Wrangling widgets",
  "Aligning covariance matrices",
  "Asserting that P equals NP",
  "Deciding whether to show this message",
  "Estimating the cosmic constant",
  "Generating witty dialogue",
  "Harvesting simoleons",
  "Juggling torpedoes",
  "Maximising the window",
  "Moulding pixels",
  "Re-evaluating the simulation",
  "Reconsidering the meaning of life",
  "Reconfiguring the office workstation",
  "Reinventing the wheel",
  "Restructuring the economy",
  "Synthesising the molecule",
  "Tying up loose ends",
  "Weaving the fabric of reality",
  "Baking cookies",
  "Calibrating the calibrator",
  "Negotiating with the llama wrangler",
  // ---- Home Assistant flavoured nonsense ----------------------------------
  "Reticulating your Zigbee mesh",
  "Convincing the light bulb it wants to be on",
  "Teaching the thermostat to love",
  "Herding smart plugs",
  "Asking the motion sensor if anyone is really there",
  "Bribing the humidity sensor",
  "Negotiating a treaty between two smart bulbs",
  "Teaching the vacuum to fear stairs",
  "Convincing the door lock it is among friends",
  "Awakening the slumbering Raspberry Pi",
  "Cataloguing every dust particle as a sensor",
  "Pleading with the weather integration to commit",
  "Reconciling two temperature sensors that disagree",
  "Teaching the curtain motor a sense of timing",
  "Reticulating the Wi-Fi into a pretzel",
  "Reminding the energy meter that honesty is a virtue",
  "Apologising to the Bluetooth beacon",
  "Convincing the fan it is, in fact, a fan",
  "Polishing each pixel by hand",
  "Asking the smoke detector to please relax",
  "Resolving a long-standing grudge between two switches",
  "Teaching the robot mop the concept of corners",
];

const SIMS2_HINTS = [
  "Click the plumbob for a fresh task.",
  "Plumbob mood reflects system morale.",
  "Tip: pressing refresh also reticulates splines.",
];

class Sims2LoadingCard extends HTMLElement {
  constructor() {
    super();
    const shadow = this.attachShadow({ mode: "open" });
    this._shadow = shadow;
    this._config = {};
    this._hass = null;
    this._tipIndex = 0;
    this._tipTimer = null;
    this._hideTimer = null;
    this._moodTimer = null;
    this._mood = "green";
    this._attached = false;
  }

  static getStubConfig() {
    return {
      wordmark: "PLEASANTVIEW",
      duration: 6,
      fullscreen: true,
    };
  }

  setConfig(config) {
    if (!config) {
      throw new Error("Invalid configuration for sims2-loading");
    }
    this._config = {
      wordmark: "THE SIMS 2",
      duration: 6,
      fullscreen: true,
      persistent: false,
      plumbob: true,
      tips: SIMS2_DEFAULT_TIPS,
      hint: true,
      dismiss_entity: null,
      dismiss_state: ["loaded", "on", "idle", "home", "ok"],
      ...config,
    };
    if (!Array.isArray(this._config.tips) || this._config.tips.length === 0) {
      this._config.tips = SIMS2_DEFAULT_TIPS;
    }
    this._render();
  }

  // Home Assistant passes the hass object here.
  set hass(value) {
    this._hass = value;
    if (this._config.dismiss_entity && value) {
      const state = value.states[this._config.dismiss_entity];
      if (state && this._config.dismiss_state.includes(state.state)) {
        this._dismiss();
      }
    }
  }

  getCardSize() {
    return this._config && this._config.fullscreen ? 8 : 3;
  }

  connectedCallback() {
    this._attached = true;
    this._startTimers();
  }

  disconnectedCallback() {
    this._attached = false;
    this._clearTimers();
  }

  _clearTimers() {
    if (this._tipTimer) {
      clearInterval(this._tipTimer);
      this._tipTimer = null;
    }
    if (this._hideTimer) {
      clearTimeout(this._hideTimer);
      this._hideTimer = null;
    }
    if (this._moodTimer) {
      clearInterval(this._moodTimer);
      this._moodTimer = null;
    }
  }

  _startTimers() {
    this._clearTimers();
    if (!this._attached) return;
    // Rotate the tip text.
    this._tipTimer = setInterval(() => this._rotateTip(), 2800);
    // Cycle the plumbob mood for ambient life.
    this._moodTimer = setInterval(() => this._cycleMood(), 4200);
    // Auto-dismiss unless persistent or duration is zero.
    if (!this._config.persistent && this._config.duration > 0) {
      this._hideTimer = setTimeout(() => this._dismiss(), this._config.duration * 1000);
    }
  }

  _rotateTip() {
    this._tipIndex = (this._tipIndex + 1) % this._config.tips.length;
    const tipEl = this._shadow.getElementById("sims2-tip");
    if (tipEl) {
      tipEl.classList.remove("sims2-tip-enter");
      // force reflow so the animation can replay
      void tipEl.offsetWidth;
      tipEl.textContent = this._config.tips[this._tipIndex];
      tipEl.classList.add("sims2-tip-enter");
    }
  }

  _cycleMood() {
    const moods = ["green", "yellow", "red"];
    this._mood = moods[(moods.indexOf(this._mood) + 1) % moods.length];
    this._applyMood();
  }

  _applyMood() {
    const plumbob = this._shadow.getElementById("sims2-plumbob");
    if (plumbob) {
      plumbob.setAttribute("data-mood", this._mood);
    }
  }

  _nextTipManual() {
    // Shuffle the order a touch so repeated clicks feel fresh.
    this._tipIndex = Math.floor(Math.random() * this._config.tips.length);
    this._rotateTip();
  }

  _dismiss() {
    const overlay = this._shadow.getElementById("sims2-loading");
    if (!overlay || overlay.dataset.dismissed === "true") return;
    overlay.dataset.dismissed = "true";
    overlay.classList.add("sims2-fading");
    this._clearTimers();
    setTimeout(() => {
      if (overlay && overlay.parentNode) {
        overlay.style.display = "none";
      }
    }, 700);
  }

  _render() {
    const cfg = this._config;
    const fullscreenClass = cfg.fullscreen ? " sims2-fullscreen" : "";
    const startTip = cfg.tips[0] || "Reticulating splines";
    const hint = cfg.hint ? SIMS2_HINTS[0] : "";

    this._shadow.innerHTML = `
      <style>${Sims2LoadingCard._styles()}</style>
      <div id="sims2-loading" class="sims2-loading${fullscreenClass}" data-mood="green">
        <div class="sims2-stars" aria-hidden="true"></div>
        <div class="sims2-content">
          ${cfg.plumbob ? `
            <div id="sims2-plumbob" class="sims2-plumbob" data-mood="green" title="Click for a fresh task"></div>` : ""}
          <div class="sims2-wordmark">${this._escapeHtml(cfg.wordmark)}</div>
          <div class="sims2-tip-row">
            <span class="sims2-dot"></span>
            <span id="sims2-tip" class="sims2-tip sims2-tip-enter">${this._escapeHtml(startTip)}</span>
          </div>
          ${hint ? `<div class="sims2-hint">${this._escapeHtml(hint)}</div>` : ""}
        </div>
      </div>
    `;

    const plumbob = this._shadow.getElementById("sims2-plumbob");
    if (plumbob) {
      plumbob.addEventListener("click", () => this._nextTipManual());
    }
    this._applyMood();
    if (this._attached) {
      this._startTimers();
    }
  }

  _escapeHtml(text) {
    if (text === null || text === undefined) return "";
    return String(text)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#39;");
  }

  static _styles() {
    return `
      :host { display: block; }
      .sims2-loading {
        position: relative;
        overflow: hidden;
        border-radius: 14px;
        min-height: 360px;
        background:
          radial-gradient(120% 90% at 50% 0%, var(--sims2-sky-top, #2E76AE) 0%, var(--sims2-sky-mid, #1E5C92) 45%, var(--sims2-sky-bottom, #0E2C4D) 100%);
        font-family: var(--sims2-font-display, "Fredoka", "Segoe UI", system-ui, sans-serif);
        color: #FFF6E0;
        display: flex;
        align-items: center;
        justify-content: center;
        transition: opacity 0.7s ease, transform 0.7s ease;
        box-shadow: inset 0 0 0 2px rgba(224, 182, 107, 0.35), 0 6px 20px rgba(0,0,0,0.35);
      }
      .sims2-fullscreen {
        position: fixed;
        inset: 0;
        z-index: 99999;
        border-radius: 0;
        min-height: 100vh;
      }
      .sims2-fading { opacity: 0; transform: scale(1.02); }

      .sims2-stars {
        position: absolute; inset: 0; pointer-events: none;
        background-image:
          radial-gradient(1.5px 1.5px at 12% 22%, rgba(255,255,255,0.7), transparent),
          radial-gradient(1.5px 1.5px at 78% 14%, rgba(255,255,255,0.6), transparent),
          radial-gradient(1.5px 1.5px at 38% 70%, rgba(255,255,255,0.5), transparent),
          radial-gradient(2px 2px at 88% 64%, rgba(255,255,255,0.6), transparent),
          radial-gradient(1px 1px at 58% 40%, rgba(255,255,255,0.5), transparent),
          radial-gradient(1px 1px at 25% 55%, rgba(255,255,255,0.45), transparent);
        opacity: 0.8;
      }

      .sims2-content { position: relative; text-align: center; padding: 24px; z-index: 1; }

      /* ---- The plumbob -------------------------------------------------- */
      .sims2-plumbob {
        width: 86px; height: 110px;
        margin: 0 auto 18px;
        cursor: pointer;
        clip-path: polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%);
        background: linear-gradient(105deg,
          #B7F36B 0%, #7BC942 42%, #4E9A26 58%, #2F6B12 100%);
        animation: sims2-float 3.2s ease-in-out infinite;
        filter: drop-shadow(0 0 14px rgba(123, 201, 66, 0.85));
        transition: filter 0.6s ease, background 0.6s ease;
      }
      .sims2-plumbob[data-mood="yellow"] {
        background: linear-gradient(105deg, #FFE079 0%, #F2C14E 42%, #C28A1F 58%, #8A5E0E 100%);
        filter: drop-shadow(0 0 14px rgba(242, 193, 78, 0.85));
      }
      .sims2-plumbob[data-mood="red"] {
        background: linear-gradient(105deg, #FF9A8A 0%, #E55B45 42%, #B03320 58%, #6E1C10 100%);
        filter: drop-shadow(0 0 14px rgba(229, 91, 69, 0.85));
      }
      .sims2-plumbob::after {
        /* centre ridge / facet highlight */
        content: ""; display: block;
        width: 2px; height: 100%; margin: 0 auto;
        background: linear-gradient(to bottom, rgba(255,255,255,0.55), rgba(255,255,255,0) 50%, rgba(0,0,0,0.25));
      }
      @keyframes sims2-float {
        0%, 100% { transform: translateY(0) rotate(0deg); }
        50%      { transform: translateY(-12px) rotate(0deg); }
      }

      .sims2-wordmark {
        font-size: clamp(26px, 6vw, 54px);
        font-weight: 600;
        letter-spacing: 0.14em;
        color: #F4D886;
        text-shadow:
          0 2px 0 #8A5E0E,
          0 3px 6px rgba(0,0,0,0.45),
          0 0 22px rgba(244, 216, 134, 0.25);
        margin-bottom: 22px;
      }

      .sims2-tip-row {
        display: inline-flex; align-items: center; gap: 10px;
        font-size: clamp(14px, 2.4vw, 19px);
        color: #EAF4FF;
        background: rgba(8, 28, 50, 0.45);
        border: 1px solid rgba(224, 182, 107, 0.35);
        border-radius: 999px;
        padding: 8px 18px;
        max-width: 90%;
      }
      .sims2-dot {
        width: 9px; height: 9px; border-radius: 50%;
        background: #7BC942;
        box-shadow: 0 0 8px #7BC942;
        animation: sims2-blink 1.2s ease-in-out infinite;
      }
      @keyframes sims2-blink { 0%,100%{opacity:1} 50%{opacity:0.25} }

      .sims2-tip { white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
      .sims2-tip-enter { animation: sims2-tip-in 0.45s ease; }
      @keyframes sims2-tip-in {
        from { opacity: 0; transform: translateY(6px); }
        to   { opacity: 1; transform: translateY(0); }
      }

      .sims2-hint {
        margin-top: 18px; font-size: 12px; letter-spacing: 0.05em;
        color: rgba(234, 244, 255, 0.55);
      }

      @media (max-width: 480px) {
        .sims2-tip { white-space: normal; }
        .sims2-tip-row { border-radius: 14px; }
      }
    `;
  }
}

// Register the element and announce it to the Lovelace card picker.
customElements.define("sims2-loading", Sims2LoadingCard);

window.customCards = window.customCards || [];
window.customCards.push({
  type: "sims2-loading",
  name: "Sims 2 Loading Screen",
  description:
    "A full-screen The Sims 2 style loading screen with a floating plumbob " +
    "and rotating 'Reticulating splines' style tips.",
  preview: false,
  documentationURL: "https://github.com/n00b001/sims2ha",
});

/* ============================================================ sims2-plumbob-card.js — customElements.define(sims2-plumbob) ============================================================ */
/**
 * sims2-plumbob-card.js
 * ---------------------------------------------------------------------------
 * Custom Lovelace card:  custom:sims2-plumbob
 *
 * A decorative, floating plumbob — the diamond that floats above every Sim's
 * head — repurposed as a charming Home Assistant status indicator. Its colour
 * (green / yellow / red) reflects the state or value of a bound entity, or a
 * fixed mood you choose.
 *
 * No build step, no dependencies. Vanilla web component, Shadow DOM.
 *
 * Example configuration:
 *
 *   type: custom:sims2-plumbob
 *   title: Household Morale
 *   entity: sensor.house_mood_score      # numeric: >= green_above is green, etc.
 *   green_above: 66
 *   yellow_above: 33
 *
 *   # Or map explicit states:
 *   type: custom:sims2-plumbob
 *   title: Bella Goth
 *   entity: person.bella_goth
 *   state_map:
 *     home: green
 *     away: yellow
 *     not_home: red
 *
 * Fan tribute. "The Sims 2" and the plumbob are trademarks of Electronic Arts.
 * ---------------------------------------------------------------------------
 */

const SIMS2_PLUMBOB_DEFAULTS = {
  title: "Plumbob",
  subtitle: "",
  mood: "green",           // green | yellow | red  (used when no entity)
  size: 70,                // plumbob height in pixels
  float: true,             // gentle bob animation
  entity: null,
  green_above: 66,         // numeric thresholds
  yellow_above: 33,
  state_map: {},           // explicit { state: mood }
  unit: "",
};

class Sims2PlumbobCard extends HTMLElement {
  constructor() {
    super();
    this._shadow = this.attachShadow({ mode: "open" });
    this._config = { ...SIMS2_PLUMBOB_DEFAULTS };
    this._hass = null;
  }

  static getStubConfig() {
    return { title: "Household Morale", mood: "green", size: 70 };
  }

  setConfig(config) {
    if (!config) throw new Error("Invalid configuration for sims2-plumbob");
    this._config = { ...SIMS2_PLUMBOB_DEFAULTS, ...config };
    this._render();
  }

  set hass(value) {
    this._hass = value;
    this._update();
  }

  getCardSize() {
    return 2;
  }

  _resolveMood() {
    const cfg = this._config;
    if (!cfg.entity || !this._hass) {
      return cfg.mood || "green";
    }
    const stateObj = this._hass.states[cfg.entity];
    if (!stateObj) return cfg.mood || "green";

    const state = stateObj.state;
    if (cfg.state_map && cfg.state_map[state]) {
      return cfg.state_map[state];
    }

    const numeric = parseFloat(state);
    if (!isNaN(numeric)) {
      if (numeric >= cfg.green_above) return "green";
      if (numeric >= cfg.yellow_above) return "yellow";
      return "red";
    }

    // Sensible fallbacks for common binary-ish states.
    const onStates = ["on", "home", "active", "running", "cooling", "heating", "ok"];
    const warnStates = ["idle", "pending", "standby", "paused", "not_home", "away"];
    const offStates = ["off", "unavailable", "unknown", "error", "problem"];
    if (onStates.includes(state)) return "green";
    if (warnStates.includes(state)) return "yellow";
    if (offStates.includes(state)) return "red";
    return cfg.mood || "green";
  }

  _update() {
    const plumbob = this._shadow.getElementById("sims2-plumbob");
    const valueEl = this._shadow.getElementById("sims2-plumbob-value");
    if (!plumbob) return;
    const mood = this._resolveMood();
    plumbob.setAttribute("data-mood", mood);

    if (valueEl && this._config.entity && this._hass) {
      const stateObj = this._hass.states[this._config.entity];
      if (stateObj) {
        valueEl.textContent = `${stateObj.state}${this._config.unit || ""}`.trim();
      }
    }
  }

  _render() {
    const cfg = this._config;
    const widthPx = Math.round(cfg.size * 0.78);
    this._shadow.innerHTML = `
      <style>${Sims2PlumbobCard._styles(cfg, widthPx)}</style>
      <div class="sims2-plumbob-card">
        <div class="sims2-plumbob-wrap">
          <div id="sims2-plumbob" class="sims2-plumbob${cfg.float ? " sims2-float" : ""}" data-mood="${this._escapeAttr(cfg.mood)}"></div>
        </div>
        <div class="sims2-plumbob-text">
          <div class="sims2-title">${this._escapeHtml(cfg.title)}</div>
          ${cfg.subtitle ? `<div class="sims2-subtitle">${this._escapeHtml(cfg.subtitle)}</div>` : ""}
          ${cfg.entity ? `<div id="sims2-plumbob-value" class="sims2-value">—</div>` : ""}
        </div>
      </div>
    `;
    this._update();
  }

  _escapeHtml(text) {
    if (text === null || text === undefined) return "";
    return String(text).replace(/[&<>"']/g, (c) => ({
      "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;",
    }[c]));
  }
  _escapeAttr(text) {
    return this._escapeHtml(text);
  }

  static _styles(cfg, widthPx) {
    return `
      :host { display: block; }
      .sims2-plumbob-card {
        background: linear-gradient(180deg, #F7EDDA 0%, #EDE0C8 100%);
        border-radius: 14px;
        box-shadow: 0 2px 12px rgba(74, 51, 32, 0.12), inset 0 1px 0 rgba(255, 255, 255, 0.6);
        border: 1px solid #D4B878;
        padding: 18px 14px 16px;
        display: flex; flex-direction: column; align-items: center; gap: 12px;
        text-align: center;
        font-family: var(--sims2-font-display, "Fredoka", system-ui, sans-serif);
      }
      .sims2-plumbob-wrap { height: ${cfg.size}px; display: flex; align-items: center; }
      .sims2-plumbob {
        width: ${widthPx}px; height: ${cfg.size}px;
        clip-path: polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%);
        background: linear-gradient(105deg, #B7F36B 0%, #7BC942 42%, #4E9A26 58%, #2F6B12 100%);
        filter: drop-shadow(0 0 10px rgba(123,201,66,0.7));
        transition: filter 0.5s ease, background 0.5s ease;
      }
      .sims2-plumbob[data-mood="yellow"] {
        background: linear-gradient(105deg, #FFE079 0%, #F2C14E 42%, #C28A1F 58%, #8A5E0E 100%);
        filter: drop-shadow(0 0 10px rgba(242,193,78,0.75));
      }
      .sims2-plumbob[data-mood="red"] {
        background: linear-gradient(105deg, #FF9A8A 0%, #E55B45 42%, #B03320 58%, #6E1C10 100%);
        filter: drop-shadow(0 0 10px rgba(229,91,69,0.75));
      }
      .sims2-float { animation: sims2plum-float 3.2s ease-in-out infinite; }
      @keyframes sims2plum-float {
        0%,100% { transform: translateY(0); }
        50%     { transform: translateY(-7px); }
      }
      .sims2-plumbob-text { color: var(--primary-text-color, #4A3320); }
      .sims2-title {
        font-size: 17px; font-weight: 600; letter-spacing: 0.02em;
        color: var(--primary-text-color, #4A3320);
      }
      .sims2-subtitle {
        font-size: 12px; margin-top: 2px;
        color: var(--secondary-text-color, #7A5A38);
      }
      .sims2-value {
        font-size: 13px; margin-top: 6px; letter-spacing: 0.04em;
        color: var(--secondary-text-color, #7A5A38);
        text-transform: capitalize;
      }
    `;
  }
}

customElements.define("sims2-plumbob", Sims2PlumbobCard);

window.customCards = window.customCards || [];
window.customCards.push({
  type: "sims2-plumbob",
  name: "Sims 2 Plumbob",
  description:
    "A floating plumbob that turns green, yellow, or red to reflect the state " +
    "of a bound entity. The Sim above your smart home.",
  preview: false,
  documentationURL: "https://github.com/n00b001/sims2ha",
});

/* ============================================================ sims2-panel-card.js — customElements.define(sims2-panel) ============================================================ */
/**
 * sims2-panel-card.js
 * ---------------------------------------------------------------------------
 * Custom Lovelace card:  custom:sims2-panel
 *
 * Wraps child cards in a Sims 2-styled curved panel with an arched top edge,
 * gold trim, and optional title/icon. Entity state drives auto-colouring
 * (green / yellow / red mood) that tints the arch glow.
 *
 * No build step, no dependencies. Vanilla web component, Shadow DOM.
 *
 * Example configuration:
 *
 *   type: custom:sims2-panel
 *   title: Living Room
 *   icon: sims2:cheerful
 *   entity: sensor.living_room_temperature
 *   green_above: 70
 *   yellow_above: 40
 *   children:
 *     - type: entities
 *       entities:
 *         - light.lamp
 *         - climate.thermostat
 *
 * Fan tribute. "The Sims 2" and the plumbob are trademarks of Electronic Arts.
 * ---------------------------------------------------------------------------
 */

const SIMS2_PANEL_DEFAULTS = {
  title: "",
  icon: null,
  entity: null,
  green_above: 66,
  yellow_above: 33,
  children: [],
};

class Sims2PanelCard extends HTMLElement {
  constructor() {
    super();
    this._shadow = this.attachShadow({ mode: "open" });
    this._config = { ...SIMS2_PANEL_DEFAULTS };
    this._hass = null;
  }

  static getStubConfig() {
    return { title: "Panel Title" };
  }

  setConfig(config) {
    if (!config) {
      throw new Error("Invalid configuration for sims2-panel");
    }
    this._config = { ...SIMS2_PANEL_DEFAULTS, ...config };
    this._render();
  }

  set hass(value) {
    this._hass = value;
    this._update();
  }

  getCardSize() {
    return 3 + (this._config.children || []).length;
  }

  // ------------------------------------------------------------------ mood
  _resolveMood() {
    const cfg = this._config;
    if (!cfg.entity || !this._hass) {
      return "green";
    }
    const stateObj = this._hass.states[cfg.entity];
    if (!stateObj) return "green";

    const state = stateObj.state;

    // Numeric thresholds
    const numeric = parseFloat(state);
    if (!isNaN(numeric)) {
      if (numeric >= cfg.green_above) return "green";
      if (numeric >= cfg.yellow_above) return "yellow";
      return "red";
    }

    // State-map lookup
    if (cfg.state_map && cfg.state_map[state]) {
      return cfg.state_map[state];
    }

    // Sensible fallbacks for common binary-ish states
    const onStates = [
      "on",
      "home",
      "active",
      "running",
      "cooling",
      "heating",
      "ok",
    ];
    const warnStates = [
      "idle",
      "pending",
      "standby",
      "paused",
      "not_home",
      "away",
    ];
    const offStates = [
      "off",
      "unavailable",
      "unknown",
      "error",
      "problem",
    ];
    if (onStates.includes(state)) return "green";
    if (warnStates.includes(state)) return "yellow";
    if (offStates.includes(state)) return "red";
    return "green";
  }

  _update() {
    const card = this._shadow.getElementById("sims2-panel-card");
    if (!card) return;
    const mood = this._resolveMood();
    card.setAttribute("data-mood", mood);
  }

  // --------------------------------------------------------------- rendering
  _render() {
    const cfg = this._config;
    this._shadow.innerHTML = `
      <style>${Sims2PanelCard._styles(cfg)}</style>
      <div id="sims2-panel-card" class="sims2-panel" data-mood="${this._escapeAttr(this._resolveMood())}">
        <div class="sims2-panel-arch"></div>
        ${cfg.title || cfg.icon ? this._renderHeader() : ""}
        <div class="sims2-panel-body">
          ${this._renderChildren()}
        </div>
      </div>
    `;
    this._update();
  }

  _renderHeader() {
    const cfg = this._config;
    let iconHtml = "";
    if (cfg.icon) {
      iconHtml = `<span class="sims2-panel-icon">${this._escapeHtml(cfg.icon)}</span>`;
    }
    return `
      <div class="sims2-panel-title-row">
        ${iconHtml}
        ${cfg.title ? `<span class="sims2-panel-title">${this._escapeHtml(cfg.title)}</span>` : ""}
      </div>
    `;
  }

  _renderChildren() {
    const children = this._config.children || [];
    if (!children.length) {
      return '<div class="sims2-panel-empty">Place HA cards directly inside this view.</div>';
    }
    // The panel card wraps child content in a Sims 2-styled container.
    // Each child entry is rendered as a styled section; actual Lovelace cards
    // are added by placing them directly in the dashboard (the panel is a
    // decorative wrapper, not a Lovelace card host).
    return children
      .map(
        (child, i) => `
      <div class="sims2-child-card" data-child-index="${i}">
        ${
          child.title || child.icon
            ? `<div class="sims2-child-header">
                ${child.icon ? `<span class="sims2-child-icon">${this._escapeHtml(child.icon)}</span>` : ""}
                ${child.title ? `<span class="sims2-child-title">${this._escapeHtml(child.title)}</span>` : ""}
              </div>`
            : ""
        }
        <div class="sims2-child-content"></div>
      </div>
    `
      )
      .join("");
  }

  // ---------------------------------------------------------------- helpers
  _escapeHtml(text) {
    if (text === null || text === undefined) return "";
    return String(text).replace(/[&<>"']/g, (c) => ({
      "&": "&amp;",
      "<": "&lt;",
      ">": "&gt;",
      '"': "&quot;",
      "'": "&#39;",
    }[c]));
  }

  _escapeAttr(text) {
    return this._escapeHtml(text);
  }

  // ------------------------------------------------------------------ styles
  static _styles(cfg) {
    const titleRowHeight = cfg.title || cfg.icon ? "42px" : "0";
    return `
      :host { display: block; }

      /* ---- Panel shell ------------------------------------------------ */
      .sims2-panel {
        position: relative;
        border-radius: 16px;
        overflow: hidden;
        background: linear-gradient(180deg, #EDE0C8 0%, #F5EBD8 100%);
        font-family: var(--sims2-font-display, "Benguiat Gothic", "Fredoka", system-ui, sans-serif);
        color: var(--sims2-espresso, #4A3320);
        box-shadow:
          inset 0 1px 0 rgba(255,255,255,0.1),
          0 4px 16px rgba(0, 0, 0, 0.3);
        transition: box-shadow 0.5s ease;
      }

      /* ---- Arched top edge (gold trim via pseudo-element) --------------- */
      .sims2-panel-arch {
        position: absolute;
        inset: -4px -4px auto -4px;
        height: calc(100% + 8px);
        pointer-events: none;
        z-index: 0;
        background: linear-gradient(135deg, #E0B66B, #C49A3C, #E8C878, #C49A3C);
        clip-path: polygon(
          0% 12%,
          4% 4%,
          10% 0%,
          50% 0%,
          90% 0%,
          96% 4%,
          100% 12%,
          100% 100%,
          0% 100%
        );
        transition: filter 0.5s ease;
      }

      /* Mood-tinted arch glow */
      .sims2-panel[data-mood="green"] .sims2-panel-arch {
        filter: drop-shadow(0 0 6px rgba(51, 204, 51, 0.45));
      }
      .sims2-panel[data-mood="yellow"] .sims2-panel-arch {
        filter: drop-shadow(0 0 6px rgba(212, 160, 32, 0.45));
      }
      .sims2-panel[data-mood="red"] .sims2-panel-arch {
        filter: drop-shadow(0 0 6px rgba(224, 64, 48, 0.45));
      }

      /* ---- Title bar -------------------------------------------------- */
      .sims2-panel-title-row {
        position: relative;
        z-index: 1;
        display: flex;
        align-items: center;
        gap: 10px;
        height: ${titleRowHeight};
        padding: 10px 20px 6px;
        background: linear-gradient(180deg, rgba(224, 182, 107, 0.15) 0%, rgba(224, 182, 107, 0.05) 100%);
        border-bottom: 1px solid rgba(224, 182, 107, 0.4);
        font-size: 16px;
        font-weight: 600;
        letter-spacing: 0.04em;
      }
      .sims2-panel-icon {
        display: inline-flex;
        align-items: center;
        justify-content: center;
        width: 22px;
        height: 22px;
        font-size: 14px;
        color: var(--sims2-gold-dark, #C49A3C);
      }
      .sims2-panel-title {
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
      }

      /* ---- Body ------------------------------------------------------- */
      .sims2-panel-body {
        position: relative;
        z-index: 1;
        padding: 14px 16px 18px;
        display: flex;
        flex-direction: column;
        gap: 12px;
      }

      /* ---- Child card wrapper ----------------------------------------- */
      .sims2-child-card {
        border-radius: 12px;
        background: var(--sims2-cream, #FBF4DF);
        border: 1px solid rgba(224, 182, 107, 0.5);
        overflow: hidden;
      }
      .sims2-child-header {
        display: flex;
        align-items: center;
        gap: 8px;
        padding: 8px 14px;
        background: linear-gradient(180deg, rgba(224, 182, 107, 0.12) 0%, rgba(224, 182, 107, 0.04) 100%);
        border-bottom: 1px solid rgba(224, 182, 107, 0.35);
        font-size: 12px;
        color: var(--sims2-espresso, #4A3320);
        letter-spacing: 0.03em;
      }
      .sims2-child-title {
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
      }
      .sims2-child-icon {
        font-size: 12px;
        color: var(--sims2-gold-dark, #C49A3C);
      }
      .sims2-child-content {
        min-height: 48px;
        padding: 10px 14px;
      }

      /* ---- Empty state ----------------------------------------------- */
      .sims2-panel-empty {
        text-align: center;
        padding: 24px 16px;
        font-size: 13px;
        color: var(--sims2-espresso, #4A3320);
        opacity: 0.45;
        letter-spacing: 0.03em;
      }

      /* ---- Mood border accents on the panel body ---------------------- */
      .sims2-panel[data-mood="green"] {
        box-shadow:
          inset 0 0 0 2px rgba(51, 204, 51, 0.35),
          0 4px 16px rgba(0, 0, 0, 0.3);
      }
      .sims2-panel[data-mood="yellow"] {
        box-shadow:
          inset 0 0 0 2px rgba(212, 160, 32, 0.35),
          0 4px 16px rgba(0, 0, 0, 0.3);
      }
      .sims2-panel[data-mood="red"] {
        box-shadow:
          inset 0 0 0 2px rgba(224, 64, 48, 0.35),
          0 4px 16px rgba(0, 0, 0, 0.3);
      }
    `;
  }
}

// Register the element and announce it to the Lovelace card picker.
customElements.define("sims2-panel", Sims2PanelCard);

window.customCards = window.customCards || [];
window.customCards.push({
  type: "sims2-panel",
  name: "Sims 2 Panel",
  description:
    "A curved panel with arched gold trim that wraps child cards in the " +
    "authentic Sims 2 live-mode control-panel look, with entity-driven mood colouring.",
  preview: false,
  documentationURL: "https://github.com/n00b001/sims2ha",
});

/* ============================================================ sims2-gauge-card.js — customElements.define(sims2-gauge) ============================================================ */
/**
 * sims2-gauge-card.js
 * ---------------------------------------------------------------------------
 * Custom Lovelace card:  custom:sims2-gauge
 *
 * Circular SVG gauge with needle indicator, inspired by the Sims 2 needs
 * meters. Features a 270-degree arc sweep, gold outer ring, colour-coded
 * segments (green / yellow / red), and an animated needle that tracks entity
 * values. Designed as a drop-in replacement for Home Assistant's built-in
 * `type: gauge` card — it accepts the same config schema.
 *
 * The Sims 2 needs meters are circular with gold trim and coloured arc
 * segments. This card replicates that aesthetic using pure SVG in Shadow DOM.
 *
 * No build step, no dependencies. Vanilla web component, Shadow DOM.
 *
 * Example configuration:
 *
 *   type: custom:sims2-gauge
 *   entity: sensor.living_room_temperature
 *   name: Temperature
 *   unit: "°F"
 *   min: 0
 *   max: 40
 *   severity:
 *     green: 25
 *     yellow: 18
 *     red: 10
 *
 * Fan tribute. "The Sims 2" and the plumbob are trademarks of Electronic Arts.
 * ---------------------------------------------------------------------------
 */

const SIMS2_GAUGE_DEFAULTS = {
  name: "Gauge",
  unit: "",
  min: 0,
  max: 100,
  severity: { green: 70, yellow: 40, red: 10 },
  size: 140,
  entity: null,
};

class Sims2GaugeCard extends HTMLElement {
  constructor() {
    super();
    this._shadow = this.attachShadow({ mode: "open" });
    this._config = { ...SIMS2_GAUGE_DEFAULTS };
    this._hass = null;
  }

  static getStubConfig() {
    return { name: "Power Draw", min: 0, max: 10000 };
  }

  setConfig(config) {
    if (!config) {
      throw new Error("Invalid configuration for sims2-gauge");
    }
    this._config = { ...SIMS2_GAUGE_DEFAULTS, ...config };
    this._render();
  }

  set hass(value) {
    this._hass = value;
    this._update();
  }

  getCardSize() {
    return 3;
  }

  // ------------------------------------------------------------------ value
  _resolveValue() {
    const cfg = this._config;
    if (!cfg.entity || !this._hass) return null;
    const stateObj = this._hass.states[cfg.entity];
    if (!stateObj) return null;
    const numeric = parseFloat(stateObj.state);
    return isNaN(numeric) ? null : numeric;
  }

  // ------------------------------------------------------------------ mood
  _resolveMood(value) {
    const { severity } = this._config;
    if (value >= (severity.green || 0)) return "green";
    if (value >= (severity.yellow || 0)) return "yellow";
    return "red";
  }

  // ------------------------------------------------------------------ SVG
  // Arc geometry: standard gauge shape — 120-degree sweep from -330deg to -150deg.
  // Start (upper-left) → over the top → end (upper-right).
  // Needle maps fraction [0,1] to [-330°, -150°], midpoint = -240° = straight up.
  // Center at (58, 58) in a 116x116 viewBox.
  _arcPath(r, cx, cy) {
    const startAngle = -330 * (Math.PI / 180);
    const endAngle = -150 * (Math.PI / 180);
    const x1 = cx + r * Math.cos(startAngle);
    const y1 = cy + r * Math.sin(startAngle);
    const x2 = cx + r * Math.cos(endAngle);
    const y2 = cy + r * Math.sin(endAngle);
    // large-arc-flag=1 (sweep > 180), sweep-flag=1 (clockwise)
    return `M ${x1.toFixed(2)} ${y1.toFixed(2)} A ${r} ${r} 0 1 1 ${x2.toFixed(2)} ${y2.toFixed(2)}`;
  }

  // Fraction of the 270-degree arc for a given value.
  _fraction(value) {
    const { min, max } = this._config;
    const f = (value - min) / (max - min);
    return Math.max(0, Math.min(1, f));
  }

  // Needle rotation angle: maps fraction [0,1] to [-330°, -150°].
  // Midpoint (-240°) = straight up.
  _needleAngle(fraction) {
    return -330 + fraction * 180;
  }

  // Arc length for a given fraction of the 270-degree sweep.
  _arcLength(r, fraction) {
    return 2 * Math.PI * r * (270 / 360) * fraction;
  }

  // ---------------------------------------------------------------- update
  _update() {
    const value = this._resolveValue();
    if (value === null) return;

    const fraction = this._fraction(value);
    const mood = this._resolveMood(value);
    const angle = this._needleAngle(fraction);

    // Update needle rotation.
    const needleGroup = this._shadow.getElementById("sims2-needle");
    if (needleGroup) {
      needleGroup.setAttribute("transform", `rotate(${angle.toFixed(1)}, 58, 58)`);
    }

    // Update value text.
    const valueEl = this._shadow.getElementById("sims2-gauge-value");
    if (valueEl) {
      const displayValue = Number.isInteger(value) ? value : value.toFixed(1);
      valueEl.textContent = `${displayValue}${this._config.unit || ""}`;
    }

    // Apply mood class to the gauge container.
    const gauge = this._shadow.getElementById("sims2-gauge");
    if (gauge) {
      gauge.setAttribute("data-mood", mood);
    }

    // Update needle color based on mood.
    const needle = this._shadow.querySelector(".sims2-needle-line");
    if (needle) {
      const colors = {
        green: "#33CC33",
        yellow: "#D4A020",
        red: "#E04030",
      };
      needle.setAttribute("stroke", colors[mood] || colors.green);
    }

    // Update segment visibility.
    this._updateSegments(value, fraction);
  }

  _updateSegments(value, fraction) {
    const { min, max } = this._config;
    const severity = this._config.severity || {};
    const greenThreshold = severity.green || 70;
    const yellowThreshold = severity.yellow || 40;

    // Green segment: from start up to green threshold
    const greenFrac = this._fraction(Math.min(value, greenThreshold));
    const greenLen = this._arcLength(48, greenFrac);
    const greenArc = this._shadow.querySelector(".sims2-gauge-green");
    if (greenArc) {
      greenArc.setAttribute("stroke-dasharray", `${greenLen.toFixed(1)} 302`);
    }

    // Yellow segment: from yellow threshold to green threshold
    const yellowFrac = this._fraction(Math.min(value, Math.max(greenThreshold, yellowThreshold)));
    const yellowStart = this._arcLength(48, this._fraction(yellowThreshold));
    const yellowLen = this._arcLength(48, yellowFrac) - yellowStart;
    const yellowArc = this._shadow.querySelector(".sims2-gauge-yellow");
    if (yellowArc) {
      yellowArc.setAttribute("stroke-dasharray", `${Math.max(0, yellowLen).toFixed(1)} 302`);
      yellowArc.setAttribute("stroke-dashoffset", `-${yellowStart.toFixed(1)}`);
    }

    // Red segment: from 0 to yellow threshold
    const redFrac = this._fraction(Math.min(value, yellowThreshold));
    const redLen = this._arcLength(48, redFrac);
    const redArc = this._shadow.querySelector(".sims2-gauge-red");
    if (redArc) {
      redArc.setAttribute("stroke-dasharray", `${redLen.toFixed(1)} 302`);
    }
  }

  // -------------------------------------------------------------- rendering
  _render() {
    const cfg = this._config;
    const value = this._resolveValue();
    const fraction = value !== null ? this._fraction(value) : 0.5;
    const angle = this._needleAngle(fraction);
    const mood = value !== null ? this._resolveMood(value) : "green";
    const needleColor = { green: "#33CC33", yellow: "#D4A020", red: "#E04030" }[mood];
    const displayValue =
      value !== null
        ? `${Number.isInteger(value) ? value : value.toFixed(1)}${cfg.unit || ""}`
        : "—";

    // Pre-compute arc segments for initial render.
    const severity = cfg.severity || {};
    const greenThreshold = severity.green || 70;
    const yellowThreshold = severity.yellow || 40;
    const greenFrac = this._fraction(Math.min(100, greenThreshold));
    const yellowFrac = this._fraction(Math.min(100, Math.max(greenThreshold, yellowThreshold)));
    const redFrac = this._fraction(yellowThreshold);
    const totalArc = 2 * Math.PI * 48 * (270 / 360);
    const greenLen = this._arcLength(48, greenFrac);
    const yellowStart = this._arcLength(48, redFrac);
    const yellowLen = this._arcLength(48, yellowFrac) - yellowStart;
    const redLen = this._arcLength(48, redFrac);

    this._shadow.innerHTML = `
      <style>${Sims2GaugeCard._styles(cfg)}</style>
      <div class="sims2-gauge-card" data-mood="${this._escapeAttr(mood)}">
        <svg viewBox="0 0 116 116" class="sims2-gauge-svg" xmlns="http://www.w3.org/2000/svg">
          <!-- Gold outer ring -->
          <circle cx="58" cy="58" r="54" fill="none" stroke="#E0B66B" stroke-width="1.5" opacity="0.7"/>

          <!-- Background arc track -->
          <path d="${this._arcPath(48, 58, 58)}"
                fill="none"
                stroke="#1A3A4C"
                stroke-width="8"
                stroke-linecap="round"/>

          <!-- Color segments (green, yellow, red zones) -->
          <path class="sims2-gauge-green"
                d="${this._arcPath(48, 58, 58)}"
                fill="none"
                stroke="#33CC33"
                stroke-width="8"
                stroke-linecap="butt"
                stroke-dasharray="${greenLen.toFixed(1)} ${totalArc.toFixed(1)}"
                opacity="0.5"/>

          <path class="sims2-gauge-yellow"
                d="${this._arcPath(48, 58, 58)}"
                fill="none"
                stroke="#D4A020"
                stroke-width="8"
                stroke-linecap="butt"
                stroke-dasharray="${Math.max(0, yellowLen).toFixed(1)} ${totalArc.toFixed(1)}"
                stroke-dashoffset="-${yellowStart.toFixed(1)}"
                opacity="0.5"/>

          <path class="sims2-gauge-red"
                d="${this._arcPath(48, 58, 58)}"
                fill="none"
                stroke="#E04030"
                stroke-width="8"
                stroke-linecap="butt"
                stroke-dasharray="${redLen.toFixed(1)} ${totalArc.toFixed(1)}"
                opacity="0.5"/>

          <!-- Tick marks -->
          ${this._renderTicks()}

          <!-- Needle group -->
          <g id="sims2-needle" transform="rotate(${angle.toFixed(1)}, 58, 58)">
            <line class="sims2-needle-line"
                  x1="58" y1="58" x2="58" y2="16"
                  stroke="${needleColor}"
                  stroke-width="2.5"
                  stroke-linecap="round"/>
            <circle class="sims2-needle-pivot"
                    cx="58" cy="58" r="5"
                    fill="#E0B66B"
                    stroke="#C49A3C"
                    stroke-width="1.5"/>
          </g>

          <!-- Value text -->
          <text id="sims2-gauge-value"
                x="58" y="88"
                text-anchor="middle"
                dominant-baseline="central"
                fill="var(--sims2-espresso, #4A3320)"
                font-size="14"
                font-weight="600"
                font-family="var(--sims2-font-display, 'Benguiat Gothic', 'Fredoka', system-ui, sans-serif)">${this._escapeHtml(displayValue)}</text>
        </svg>
        ${cfg.name ? `<div class="sims2-gauge-name">${this._escapeHtml(cfg.name)}</div>` : ""}
      </ha-card>
    `;
  }

  _renderTicks() {
    const ticks = [];
    const cx = 58, cy = 58;
    const innerR = 38, outerR = 42;
    const numTicks = 9;
    for (let i = 0; i <= numTicks; i++) {
      const frac = i / numTicks;
      const angleDeg = -330 + frac * 180;
      const rad = angleDeg * (Math.PI / 180);
      const x1 = cx + innerR * Math.cos(rad);
      const y1 = cy + innerR * Math.sin(rad);
      const x2 = cx + outerR * Math.cos(rad);
      const y2 = cy + outerR * Math.sin(rad);
      const isMajor = i % 3 === 0;
      ticks.push(`
        <line x1="${x1.toFixed(1)}" y1="${y1.toFixed(1)}"
              x2="${x2.toFixed(1)}" y2="${y2.toFixed(1)}"
              stroke="rgba(224,182,107,${isMajor ? 0.6 : 0.3})"
              stroke-width="${isMajor ? 1.5 : 0.8}"/>
      `);
    }
    return ticks.join("");
  }

  // ---------------------------------------------------------------- helpers
  _escapeHtml(text) {
    if (text === null || text === undefined) return "";
    return String(text).replace(/[&<>"']/g, (c) => ({
      "&": "&amp;",
      "<": "&lt;",
      ">": "&gt;",
      '"': "&quot;",
      "'": "&#39;",
    }[c]));
  }

  _escapeAttr(text) {
    return this._escapeHtml(text);
  }

  static _styles() {
    return `
      :host { display: block; }
      .sims2-gauge-card {
        background: linear-gradient(180deg, #F7EDDA 0%, #EDE0C8 100%);
        border-radius: 16px;
        box-shadow: 0 2px 12px rgba(74, 51, 32, 0.12), inset 0 1px 0 rgba(255, 255, 255, 0.6);
        border: 1px solid #D4B878;
        padding: 16px 12px 14px;
        display: flex;
        flex-direction: column;
        align-items: center;
        gap: 8px;
        text-align: center;
        font-family: var(--sims2-font-display, "Benguiat Gothic", "Fredoka", system-ui, sans-serif);
      }
      .sims2-gauge-svg {
        width: var(--_gauge-size, 140px);
        height: var(--_gauge-size, 140px);
        display: block;
      }
      .sims2-gauge-name {
        font-size: 13px;
        color: var(--secondary-text-color, #7A5A38);
        letter-spacing: 0.03em;
      }
    `;
  }
}

// Register the element and announce it to the Lovelace card picker.
customElements.define("sims2-gauge", Sims2GaugeCard);

window.customCards = window.customCards || [];
window.customCards.push({
  type: "sims2-gauge",
  name: "Sims 2 Gauge",
  description:
    "A circular SVG gauge with needle indicator and gold trim, inspired by " +
    "the Sims 2 needs meters. Drop-in replacement for Home Assistant's type:gauge.",
  preview: false,
  documentationURL: "https://github.com/n00b001/sims2ha",
});

/* ============================================================ sims2-divider-card.js — customElements.define(sims2-divider) ============================================================ */
/**
 * sims2-divider-card.js
 * ---------------------------------------------------------------------------
 * Custom Lovelace card:  custom:sims2-divider
 *
 * A decorative divider featuring a plumbob-shaped diamond separator with gold
 * gradient trim lines on either side — inspired by the Sims 2 UI section
 * dividers.
 *
 * Place it manually between sections in a dashboard to break content into
 * visually distinct areas. The mood colour (green / yellow / red) matches
 * the existing plumbob card convention.
 *
 * No build step, no dependencies. Vanilla web component, Shadow DOM.
 *
 * Example configuration:
 *
 *   type: custom:sims2-divider
 *   mood: green       # green | yellow | red (default: green)
 *   size: 30          # diamond height in pixels
 *
 * Fan tribute. "The Sims 2" and the plumbob are trademarks of Electronic Arts.
 * ---------------------------------------------------------------------------
 */

const SIMS2_DIVIDER_DEFAULTS = {
  mood: "green",
  size: 30,
};

class Sims2DividerCard extends HTMLElement {
  constructor() {
    super();
    this._shadow = this.attachShadow({ mode: "open" });
    this._config = { ...SIMS2_DIVIDER_DEFAULTS };
  }

  static getStubConfig() {
    return { mood: "green", size: 30 };
  }

  setConfig(config) {
    if (!config) {
      throw new Error("Invalid configuration for sims2-divider");
    }
    this._config = { ...SIMS2_DIVIDER_DEFAULTS, ...config };
    // Clamp mood to valid values.
    if (!["green", "yellow", "red"].includes(this._config.mood)) {
      this._config.mood = "green";
    }
    this._render();
  }

  getCardSize() {
    return 1;
  }

  _render() {
    const cfg = this._config;
    this._shadow.innerHTML = `
      <style>${Sims2DividerCard._styles(cfg)}</style>
      <div class="sims2-divider" data-mood="${this._escapeAttr(cfg.mood)}">
        <span class="sims2-divider-line-left"></span>
        <div class="sims2-divider-plumbob" data-mood="${this._escapeAttr(cfg.mood)}"></div>
        <span class="sims2-divider-line-right"></span>
      </div>
    `;
  }

  _escapeAttr(text) {
    return String(text).replace(/[&<>"']/g, (c) => ({
      "&": "&amp;",
      "<": "&lt;",
      ">": "&gt;",
      '"': "&quot;",
      "'": "&#39;",
    }[c]));
  }

  static _styles(cfg) {
    return `
      :host { display: block; }
      .sims2-divider {
        display: flex;
        align-items: center;
        justify-content: center;
        gap: 12px;
        padding: 16px 0;
      }

      /* ---- Gold gradient trim lines ----------------------------------- */
      .sims2-divider-line-left,
      .sims2-divider-line-right {
        flex: 1;
        height: 1px;
        background: linear-gradient(90deg,
          transparent 0%,
          rgba(224, 182, 107, 0.5) 30%,
          rgba(224, 182, 107, 0.6) 50%,
          rgba(224, 182, 107, 0.5) 70%,
          transparent 100%);
      }

      /* ---- Plumbob diamond -------------------------------------------- */
      .sims2-divider-plumbob {
        width: ${cfg.size}px;
        height: ${cfg.size}px;
        flex-shrink: 0;
        clip-path: polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%);
        background: linear-gradient(105deg,
          #B7F36B 0%,
          #7BC942 42%,
          #4E9A26 58%,
          #2F6B12 100%);
        filter: drop-shadow(0 0 6px rgba(123, 201, 66, 0.6));
        transition: background 0.5s ease, filter 0.5s ease;
      }

      .sims2-divider-plumbob[data-mood="yellow"] {
        background: linear-gradient(105deg,
          #FFE079 0%,
          #F2C14E 42%,
          #C28A1F 58%,
          #8A5E0E 100%);
        filter: drop-shadow(0 0 6px rgba(242, 193, 78, 0.6));
      }

      .sims2-divider-plumbob[data-mood="red"] {
        background: linear-gradient(105deg,
          #FF9A8A 0%,
          #E55B45 42%,
          #B03320 58%,
          #6E1C10 100%);
        filter: drop-shadow(0 0 6px rgba(229, 91, 69, 0.6));
      }
    `;
  }
}

// Register the element and announce it to the Lovelace card picker.
customElements.define("sims2-divider", Sims2DividerCard);

window.customCards = window.customCards || [];
window.customCards.push({
  type: "sims2-divider",
  name: "Sims 2 Divider",
  description:
    "A decorative plumbob-shaped divider with gold gradient trim lines. " +
    "Use between sections in a dashboard.",
  preview: false,
  documentationURL: "https://github.com/n00b001/sims2ha",
});

